"const { chromium } = require('playwright');
const Tesseract = require('tesseract.js');
require('dotenv').config();
const path = require('path');
const fs = require('fs');

async function solveCaptcha(imageBuffer) {
    console.log("[시스템] 캡챠 이미지가 감지되었습니다. Tesseract OCR 비전 분석을 시작합니다...");
    try {
        const { data: { text } } = await Tesseract.recognize(imageBuffer, 'eng', {
            logger: m => console.log(`[OCR 진행중] ${m.status} - ${(m.progress * 100).toFixed(2)}%`)
        });

        const cleanText = text.replace(/[^a-zA-Z0-9]/g, '').trim();
        console.log(`[시스템] OCR 해독 완료: ${cleanText}`);
        return cleanText;
    } catch (error) {
        console.error("❌ OCR 해독 실패:", error);
        return "";
    }
}

