"async function solveCaptcha(imageBuffer) {
    console.log("[시스템] 캡챠 이미지가 감지되었습니다. AI 대신 로컬 파일로 저장하고 직접 입력 받습니다...");
    try {
        const base64Image = imageBuffer.toString('base64');
        const buffer = Buffer.from(base64Image, 'base64');
        const imagePath = 'C:\\Users\\smile\\AutoBlogPublisher\\captcha.png';
        fs.writeFileSync(imagePath, buffer);
        console.log(`[시스템] 캡챠 이미지가 저장되었습니다: ${imagePath}`);
        console.log(`[ANTIGRAVITY_PROMPT] 캡챠 정답 대기 중...`);

        const readline = require('readline').createInterface({
            input: process.stdin,
            output: process.stdout
        });

