"async function solveCaptcha(imageBuffer) {
    console.log("🚨 [시스템] 캡챠 이미지를 로컬 비전 AI(llama3.2-vision)로 분석 중입니다...");
    try {
        const base64Image = imageBuffer.toString('base64');

        const response = await fetch('http://localhost:11434/api/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model: 'moondream',
                messages: [{
                    role: 'user',
                    content: '이 이미지는 캡챠 화면입니다. 화면 중앙에 "___ 부지방법원"과 같이 빈칸을 채우라는 질문이 있습니다. 먼저 질문의 빈칸 모양과 힌트를 확인하고, 위에 있는 지도에서 그 장소의 전체 이름을 찾으세요. 그리고 빈칸(____)에 들어갈 정확한 글자만 단답형으로 출력하세요. 설명이나 마침표 없이 오직 정답 글자만 말하세요. (예: 서울남)',
                    images: [base64Image]
                }],
                stream: false,
                options: { temperature: 0.1 } // 보수적으로 확실한 정답만 도출
            })
        });

        if (!response.ok) {
            console.error("AI 서버 응답 오류:", response.statusText);
            return "";
        }

        const data = await response.json();
        const answer = data.message.content.trim().replace(/\./g, ""); // 마침표 제거
        console.log(`🤖 비전 AI가 유추한 캡챠 정답: [${answer}]`);
        return answer;
    } catch (error) {
        console.error("비전 AI 처리 중 오류 발생:", error);
        return "";
    }
}"

