        const response = await fetch('http://localhost:11434/api/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model: 'gemma4:e4b',
                messages: [{
                    role: 'user',
                    content: '이 이미지는 캡챠 화면입니다. 화면 중앙에 "___ 부지방법원"과 같이 빈칸을 채우라는 질문이 있습니다. 질문의 빈칸 모양과 힌트를 확인하고, 위에 있는 지도 이미지에서 그 장소의 정확한 이름을 찾으세요. 그리고 빈칸(____)에 들어갈 정답 글자만 단답형으로 출력하세요. 설명 없이 오직 정답만 말하세요. (예: 서울남)',
                    images: [base64Image]
                }],
                stream: false,
                options: { temperature: 0.1 }
            })
        });

        if (!response.ok) {
            console.error("AI 서버 응답 오류:", response.statusText);
            return "";
        }

        const data = await response.json();
        const answer = data.message.content.trim().replace(/['".,\n]/g, ""); 
        console.log(`🤖 Gemma4가 유추한 캡챠 정답: [${answer}]`);
        return answer;
    } catch (error) {
        console.error("Gemma4 비전 처리 중 오류 발생:", error);
        return "";
    }
}"

