"        // ==========================================
        // 2. 팝업 닫기 및 제목 입력
        // ==========================================
        console.log("👉 스마트에디터 방해 팝업(도움말/임시저장) 닫기 시도...");
        await page.waitForTimeout(3000); // 팝업이 뜰 때까지 충분히 대기

        const closePopupsInFrame = async () => {
            try {
                // Playwright locator 방식 (시간을 충분히 줌)
                const cancelBtn = frame.locator('text="취소"').last();
                if (await cancelBtn.isVisible({ timeout: 2000 })) {
                    await cancelBtn.click({ force: true });
                    console.log("✅ 임시저장 '취소' 텍스트 클릭 성공!");
                }
            } catch(e) {}

            try {
                // JS 강제 실행 방식 (frame 내부)
                await frame.evaluate(() => {
                    const elements = Array.from(document.querySelectorAll('*'));
                    const cancelEl = elements.find(el => el.textContent === '취소');
                    if (cancelEl) cancelEl.click();
                });
            } catch(e) {}
        };

        await closePopupsInFrame();

        // 최후의 수단 1: ESC 키 (취소)
        await page.keyboard.press('Escape');
        await page.waitForTimeout(500);
        // 최후의 수단 2: Enter 키 (만약 취소가 안 되면 그냥 '확인' 누르고 기존 글 덮어씌우기)
        await page.keyboard.press('Enter');
        await page.waitForTimeout(1000);"

