"const { execSync } = require('child_process');
const path = require('path');

/**
 * DEPRECATED: This script previously tried to use 'gemma:latest' (a text model) to generate images, which caused errors.
 * 
 * NEW KAGGLE 2.0 FLOW:
 * This script now delegates image generation to the Python Kaggle 2.0 pipeline (gradio_auto.py).
 * The Python pipeline will:
 * 1. Read the article content.
 * 2. Use Llama 3.1 to generate a highly detailed SDXL prompt (Memory Separation Phase 1).
 * 3. Call the remote Kaggle SDXL Gradio endpoint to generate the image (Memory Separation Phase 2).
 */

async function generateImages() {
    console.log("🚀 [Kaggle 2.0 Image Batch] 파이썬 하이브리드 파이프라인으로 이미지 생성을 위임합니다...");

    // 이 예제에서는 기본 테스트 폴더를 지정합니다. 실제 운영에서는 반복문으로 폴더를 돌립니다.
    const targetFolder = path.join(__dirname, '..', 'blog_auto', 'contents', 'post_01');
    const pythonScript = path.join(__dirname, 'gradio_auto.py');

    try {
        console.log(`\n실행 중: python ${pythonScript} "${targetFolder}"`);
        const result = execSync(`python "${pythonScript}" "${targetFolder}"`, { encoding: 'utf-8' });
        console.log(result);
    } catch (e) {
        console.error(`❌ 파이프라인 실행 중 에러 발생: ${e.message}`);
    }

    console.log(`\n🎉 작업 완료! 썸네일 생성이 Kaggle 2.0 파이프라인을 통해 처리되었습니다.`);
}

generateImages();"

